import React, {useState, useEffect} from 'react'
import {Menu} from 'antd'

import './navbarComponent.scss'

function Navbar(){
    const [selectedKey, setSelectedKey] = useState('home')
    const [blockPosition, setBlockPosition] = useState('center')

    const handleClick = (e)=>{
        const anchor = document.getElementById(`${e.key}`)
        anchor.scrollIntoView({ behavior: 'smooth', block: blockPosition})
        setSelectedKey(`${e.key}`)
    }

    useEffect(()=>{
        setPosition()
        window.addEventListener('resize', setPosition)
        return () => window.removeEventListener('resize', setPosition);
    })

    const setPosition = ()=>{
        if(window.innerWidth <= 760){
            setBlockPosition('start')
        }else{
            setBlockPosition('center')
        }
    }

    return(
        <Menu onClick={handleClick} mode="horizontal" selectedKeys={[selectedKey]} className='navbar'>
            <Menu.Item key="home">
                About
            </Menu.Item>
            <Menu.Item key="skills">
                Skills
            </Menu.Item>
            <Menu.Item key="experience">
                Experience
            </Menu.Item>
            <Menu.Item key="contact">
                Contact
            </Menu.Item>
      </Menu>
    )
}

export default Navbar